#include <vector>
#include <algorithm>
#include <iostream>

/**
 * @brief Constructs a new array by appending the reverse of the input array to the original array.
 * 
 * @param nums The input integer array.
 * @return std::vector<long long> The resulting array of length 2*n.
 */
std::vector<long long> solve(std::vector<long long> nums) {
    int n = nums.size();
    // The resulting array 'ans' has length 2*n
    std::vector<long long> ans(2 * n);

    // First n elements are the same as nums: ans[i] = nums[i]
    for (int i = 0; i < n; ++i) {
        ans[i] = nums[i];
    }

    // Last n elements are the reverse of nums: ans[i + n] = nums[n - i - 1]
    for (int i = 0; i < n; ++i) {
        // The index in the reversed part (from 0 to n-1) is i.
        // The corresponding index in nums for the reversed part is n - 1 - i.
        // This element is placed at index i + n in ans.
        ans[i + n] = nums[n - 1 - i];
    }

    return ans;
}
